/// <summary>
/// Updates this record's inventory dimensions with the given inventory location ID.
/// </summary>
/// <param name="_wMSLocationId">
/// The location number ID to set.
/// </param>
[Hookable(false)]
internal void setWMSLocationId(WMSLocationId _wMSLocationId)
{
    InventDim inventDim = InventDim::find(this.InventDimId);

    if (inventDim.WMSLocationId != _wMSLocationId)
    {
        WMSLocation jobWMSLocation = WMSLocation::find(_wMSLocationId, inventDim.InventLocationId);

        inventDim.WMSLocationId = jobWMSLocation.WMSLocationId;
        this.InventDimId = InventDim::findOrCreate(inventDim).inventDimId;
    }
}
